<!DOCTYPE html>
<html lang="fr">
<head>
    <meta charset="UTF-8">
    <title>Compteur à rebours personnalisé</title>
    <script>
        let countdown, events = {};

        function startCountdown(eventId) {
            const event = events[eventId];
            if (event) {
                countdown = setInterval(() => {
                    event.time -= 1000;
                    updateCountdown(event);
                    if (event.time <= 0) {
                        clearInterval(countdown);
                        speak("This is the end");
                        speak(`${event.name} est terminé.`);
                    } else if (event.time <= 60 * 15 * 1000) {
                        speak(`You have 15 minutes left for ${event.name}`);
                    } else if (event.time <= 60 * 5 * 1000) {
                        speak(`You have 5 minutes left for ${event.name}`);
                    } else {
                        speak(`Salut, ${event.name} commence dans ${Math.floor(event.time / 1000)} secondes`);
                    }
                }, 1000);
            }
        }

        function updateCountdown(event) {
            const minutes = Math.floor(event.time / 60000);
            const seconds = ((event.time % 60000) / 1000).toFixed(0);
            document.getElementById(`countdown-${event.id}`).textContent = `${minutes}:${seconds.padStart(2, '0')}`;
        }

        function speak(text) {
            const utterance = new SpeechSynthesisUtterance(text);
            speechSynthesis.speak(utterance);
        }

        function createEvent(name, duration) {
            events[name] = {
                name: name,
                time: duration * 60 * 1000,
                id: Object.keys(events).length
            };
            startCountdown(events[name].id);
        }

        document.addEventListener('DOMContentLoaded', () => {
            speak('Salut!');
            speak('Bienvenue dans ton compteur à rebours personnalisé!');
