#include <unistd.h>
#include <sys/wait.h>
#include <sys/types.h>
#include <fcntl.h>

int main() {
    int pipefd[2];
    pipe(pipefd);

    pid_t pid = fork();
    if (pid == 0) { // Child process
        // Close unused ends of pipe
        close(pipefd[1]);
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);
        close(pipefd[0]);

        execlp("your_command_here", "your_command_here", (char*)NULL);
        std::cerr << "execlp failed" << std::endl;
        exit(1);
    } else if (pid > 0) { // Parent process
        // Close the read end of the pipe
        close(pipefd[0]);
        // Continue with your operations with the child process
    } else {
        std::cerr << "fork failed" << std::endl;
    }

    return 0;
}
```

